{
  "formal_minutes": {
    "회의코드": "PUBLIC_MEETING_SMOKE",
    "회의명": "UI Theme Package Release Readiness",
    "참석자": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "confirmed_decisions": [
      {
        "내용": "공개 릴리스 목표 시각은 스모크 테스트 통과 시 금요일 15:00 KST로 한다.",
        "근거": "도윤이 스모크 테스트 선행 필요를 제기했고, 최종 결정으로 금요일 15:00 KST 조건부 목표가 확정됨."
      },
      {
        "내용": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "근거": "스크립트에서 packageName mismatch를 무시하자는 제안은 기각되었고, 대체 판단 기준이 최종 결정됨."
      }
    ],
    "rejected_proposals": [
      {
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "결론": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "내용": "수요일 릴리스 제안",
        "상태": "내부 스트레치 골",
        "비고": "확정 공개 릴리스 일정이 아니며 스모크 테스트 통과 전에는 성립하지 않음."
      }
    ],
    "non_decisions": [
      {
        "내용": "README 설치 절차는 가능하면 목요일까지 검토 필요 의견이 있었으나, 담당자 지정은 없었다."
      }
    ],
    "risks": [
      {
        "내용": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "내용": "README 설치 절차가 오래된 상태이면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "도윤",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "담당자 미지정",
      "source_certainty": "tentative"
    },
    {
      "owner": "하라",
      "task": "민준의 스모크 결과 공유 후 생성된 tarball 경로를 점검한다.",
      "due": null,
      "status": "확정",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "민준의 스모크 테스트 재실행 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "도윤의 failure triage note가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인한다.",
      "스모크 통과 여부를 전제로 공개 릴리스 목표인 금요일 15:00 KST 진행 가능성을 재확인한다.",
      "하라의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 골 언급 여부를 후속 의제로 남긴다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "회의 기록에 없는 고객명, 외부 파트너명, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자가 지정되지 않은 항목에는 임의의 소유자를 넣지 않는다.",
    "정확한 마감이 없는 항목에는 임의의 날짜나 시간을 넣지 않는다.",
    "수요일 제안은 확정 일정이 아니라 내부 스트레치 골로만 유지한다.",
    "기각된 제안과 확정된 결정을 혼합하지 않는다.",
    "열린 질문은 답이 정해진 것처럼 서술하지 않는다."
  ]
